class LoginComponent {
    constructor(snack, login, router) {
        this.snack = snack;
        this.login = login;
        this.router = router;
        this.loginData = {
            username: '',
            password: '',
        };
    }
    ngOnInit() { }
    formSubmit() {
        console.log('login btn clicked');
        if (this.loginData.username.trim() == '' ||
            this.loginData.username == null) {
            this.snack.open('Username is required !! ', '', {
                duration: 3000,
            });
            return;
        }
        if (this.loginData.password.trim() == '' ||
            this.loginData.password == null) {
            this.snack.open('Password is required !! ', '', {
                duration: 3000,
            });
            return;
        }
        //request to server to generate token
        this.login.generateToken(this.loginData).subscribe((data) => {
            console.log('success');
            console.log(data);
            //login...
            this.login.loginUser(data.token);
            this.login.getCurrentUser().subscribe((user) => {
                this.login.setUser(user);
                console.log(user);
                //redirect ...ADMIN: admin-dashboard
                //redirect ...NORMAL:normal-dashboard
                const role = this.login.getUserRole();
                if (role == 'ADMIN') {
                    this.router.navigate(['admin']);
                    this.login.loginStatusSubject.next(true);
                }
                else if (role == 'NORMAL' || role == 'STUDENT' || role == 'TEACHER') {
                    this.router.navigate(['user-dashboard/0']);
                    this.login.loginStatusSubject.next(true);
                }
                else if (role == 'SUPER_ADMIN') {
                    this.router.navigate(['super-admin/dashboard']);
                    this.login.loginStatusSubject.next(true);
                }
                else if (role == 'SCHOOL_ADMIN') {
                    this.router.navigate(['school-admin/dashboard']);
                    this.login.loginStatusSubject.next(true);
                }
                else {
                    this.login.logout();
                }
            });
        }, (error) => {
            console.log('Error !');
            console.log(error);
            this.snack.open('Invalid Details !! Try again', '', {
                duration: 3000,
            });
        });
    }
}
