    constructor(schoolService, loginService) {
        this.schoolService = schoolService;
        this.loginService = loginService;
        this.tenantId = '';
        this.classes = [];
        this.loading = true;
        this.showForm = false;
        this.saving = false;
        this.deleteConfirmId = null;
        this.newClass = { name: '', section: '', description: '', tenantId: '' };
        this.classColors = [
            '#2563eb', '#7c3aed', '#059669', '#d97706', '#dc2626',
            '#0891b2', '#be185d', '#065f46', '#92400e', '#1e40af'
        ];
        this.sections = ['A', 'B', 'C', 'D', 'E'];
        this.classNames = [
            'Nursery', 'KG-1', 'KG-2',
            'Class 1', 'Class 2', 'Class 3', 'Class 4', 'Class 5',
            'Class 6', 'Class 7', 'Class 8', 'Class 9', 'Class 10',
            'Class 11', 'Class 12'
        ];
    }
    ngOnInit() {
        this.tenantId = this.loginService.getTenantId();
        this.load();
    }
    load() {
        this.loading = true;
        this.schoolService.getClasses(this.tenantId).subscribe({
            next: (data) => { this.classes = data || []; this.loading = false; },
            error: () => { this.classes = []; this.loading = false; }
        });
    }
    colorFor(i) {
        return this.classColors[i % this.classColors.length];
    }
    openForm() {
        this.newClass = { name: '', section: '', description: '', tenantId: this.tenantId };
        this.showForm = true;
    }
    saveClass() {
        if (!this.newClass.name.trim())
            return;
        this.saving = true;
        this.schoolService.createClass(Object.assign(Object.assign({}, this.newClass), { tenantId: this.tenantId })).subscribe({
            next: () => { this.saving = false; this.showForm = false; this.load(); },
            error: () => { this.saving = false; }
        });
    }
    confirmDelete(id) {
        this.deleteConfirmId = id;
    }
    deleteClass() {
        if (this.deleteConfirmId == null)
            return;
        this.schoolService.deleteClass(this.deleteConfirmId).subscribe({
            next: () => { this.deleteConfirmId = null; this.load(); },
            error: () => { this.deleteConfirmId = null; }
        });
    }
